import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface RatingDistribution {
  stars: number;
  count: number;
}

interface ProductData {
  product: {
    name: string;
    averageRating: number;
    reviewCount: number;
  };
  ratingDistribution: RatingDistribution[];
}

export default function Widget() {
  const productData = response.data as ProductData;
  const { product, ratingDistribution } = productData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107' }}>
              {product.name}
            </Typography>
            <Typography variant="body1" sx={{ color: '#FFFFFF' }}>
              Average Rating: {product.averageRating} / 5
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              {product.reviewCount} Reviews
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: ratingDistribution.map(r => r.count),
                  color: '#FFB300',
                  label: 'Ratings',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: ratingDistribution.map(r => `${r.stars} Stars`),
                  id: 'stars',
                },
              ]}
              yAxis={[{ id: 'count' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="stars"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="count"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
